#!/bin/bash
# Two-step oracle note experiment on SciVideoBench.
# Assumes Step 1 and Step 2 notes have been generated by generate_oracle_notes_2step.py.
# Runs four evals with Qwen-3B as answerer, 5-GPU parallel each, and
# both with-video and note-only (leak test) variants.
set -e
cd /home/yz0392@unt.ad.unt.edu/xin_ai/scivideobench
mkdir -p logs

PY=/home/yz0392@unt.ad.unt.edu/miniconda3/envs/expvid/bin/python
MODEL=Qwen/Qwen2.5-VL-3B-Instruct
GPUS=${1:-"0,1,2,3,7"}

IFS=',' read -ra GPU_ARR <<< "$GPUS"
N=${#GPU_ARR[@]}

run_eval() {
  local tag=$1; local notes_subdir=$2; local key_mode=$3; local skip_video=$4
  echo "=== Eval: $tag ==="
  PIDS=()
  for i in "${!GPU_ARR[@]}"; do
    gpu=${GPU_ARR[$i]}
    logf="logs/${tag}_gpu${gpu}_chunk${i}of${N}.log"
    skip_flag=""
    [ "$skip_video" = "1" ] && skip_flag="--skip_video"
    CUDA_VISIBLE_DEVICES=$gpu nohup $PY evaluate_oracle_flex.py \
      --model "$MODEL" --output results_scivideobench \
      --notes_subdir "$notes_subdir" --key_mode "$key_mode" \
      --tag "$tag" $skip_flag \
      --chunk_id $i --num_chunks $N --resume \
      >> "$logf" 2>&1 &
    PIDS+=($!)
  done
  for p in "${PIDS[@]}"; do wait $p; done
  echo "  $tag DONE"
}

# 1. Step 1 only, video+note  — does plain description alone help?
run_eval c_step1_only            step1_descriptions   vid     0

# 2. Step 1 only, note-only    — leak test for step1
run_eval c_step1_only_noteonly   step1_descriptions   vid     1

# 3. Step 2 (filtered), video+note  — the answer-conditioned filter on top of step1
run_eval c_step2                 step2_oracle_notes   vid_qid 0

# 4. Step 2 (filtered), note-only  — leak test for step2
run_eval c_step2_noteonly        step2_oracle_notes   vid_qid 1

echo "ALL TWO-STEP EVALS DONE"
